	private long timeToFirstRows(int rowLimit) {
		try (var connection = repository.getConnection()) {
			connection.begin(IsolationLevels.READ_COMMITTED);
			TupleQuery tupleQuery = connection.prepareTupleQuery(query);
			tupleQuery.setMaxExecutionTime(70);
			long count = 0;
			try (TupleQueryResult result = tupleQuery.evaluate()) {
				while (count < rowLimit && result.hasNext()) {
					result.next();
					count++;
				}
			}
			connection.commit();

			long expectedCount = Math.min(expected, rowLimit);
			if (count != expectedCount) {
				throw new IllegalStateException(
						"Unexpected first-row count: expected " + expectedCount + " but got " + count);
			}

			return count;
		}
	}

	private void ensureDataLoadedAndValidated() throws IOException {
		var expectedDbFileSizes = readExpectedDbFileSizes();
		if (!hasExpectedDbFileSizes(expectedDbFileSizes)) {
			rebuildStoreFromScratch();
			expectedDbFileSizes = currentDbFileSizes();
			writeExpectedDbFileSizes(expectedDbFileSizes);
		}

		if (!hasExpectedDbFileSizes(expectedDbFileSizes)) {
			var currentDbFileSizes = currentDbFileSizes();
			throw new IllegalStateException("Unexpected LMDB db file sizes in fixed benchmark store. Expected "
					+ TRIPLES_DATA_FILE + "=" + expectedDbFileSizes.triplesDataSizeBytes + " and "
					+ VALUES_DATA_FILE + "=" + expectedDbFileSizes.valuesDataSizeBytes + " but got "
					+ TRIPLES_DATA_FILE + "=" + currentDbFileSizes.triplesDataSizeBytes + " and "
					+ VALUES_DATA_FILE + "=" + currentDbFileSizes.valuesDataSizeBytes);
		}

		if (!expectedDbFileSizeFile().isFile()) {
			writeExpectedDbFileSizes(expectedDbFileSizes);
		}
	}

	private void waitForSketchesIfEnabled() throws IOException {
		if (!Boolean.parseBoolean(System.getProperty(WAIT_FOR_SKETCHES_PROPERTY, "true"))) {
			return;
		}
		repository.init();
		long timeoutSeconds = Long.getLong(WAIT_FOR_SKETCHES_TIMEOUT_SECONDS_PROPERTY,
				DEFAULT_WAIT_FOR_SKETCHES_TIMEOUT_SECONDS);
		BenchmarkJoinEstimatorSupport.awaitEstimatorReady(store, "theme benchmark setup", timeoutSeconds,
				TimeUnit.SECONDS);
	}

	private void rebuildStoreFromScratch() throws IOException {
		File storeDirectory = storeDirectory();
		if (repository != null) {
			repository.shutDown();
		}

		FileUtils.deleteDirectory(storeDirectory);
		if (!storeDirectory.exists() && !storeDirectory.mkdirs()) {
			throw new IOException("Unable to recreate fixed LMDB benchmark directory: " + storeDirectory);
		}

		storeConfig = ConfigUtil.createConfig();
		storeConfig.setIterationCacheSyncThreshold(0);
		store = ConfigUtil.createStore(storeDirectory, storeConfig);
		repository = new SailRepository(store);
//		BenchmarkJoinEstimatorSupport.prepareEstimatorForBulkLoad(repository, store);
		loadData();
//		BenchmarkJoinEstimatorSupport.persistEstimatorAfterBulkLoad(repository, store);

		repository.shutDown();
		repository = null;
		store = null;

		System.gc();

		store = ConfigUtil.createStore(storeDirectory, storeConfig);
		repository = new SailRepository(store);
	}

	private DbFileSizes readExpectedDbFileSizes() throws IOException {
		var expectedDbFileSizeFile = expectedDbFileSizeFile();
		if (!expectedDbFileSizeFile.isFile()) {
			return missingExpectedDbFileSizes();
		}
		var properties = new Properties();
		try (var inputStream = new FileInputStream(expectedDbFileSizeFile)) {
			properties.load(inputStream);
		}
		try {
			String tripleIndexes = properties.getProperty(TRIPLE_INDEXES_PROPERTY);
			if (!storeConfig.getTripleIndexes().equals(tripleIndexes)) {
				return missingExpectedDbFileSizes();
			}
			if (externalStoreDirectoryEnabled()) {
				String compatibilityKey = properties.getProperty(STORE_COMPATIBILITY_KEY_FILE_PROPERTY);
				if (!storeCompatibilityKey().equals(compatibilityKey)) {
					throw new IllegalStateException(
							"External LMDB benchmark store compatibility key mismatch: expected "
									+ storeCompatibilityKey() + " but found " + compatibilityKey);
				}
			}
			return new DbFileSizes(
					parseSizeProperty(properties, TRIPLES_DATA_SIZE_PROPERTY),
					parseSizeProperty(properties, VALUES_DATA_SIZE_PROPERTY));
		} catch (IllegalStateException e) {
			System.out.println("Ignoring invalid expected LMDB size file " + expectedDbFileSizeFile + ": "
					+ e.getMessage());
			if (!expectedDbFileSizeFile.delete()) {
				System.out.println("Unable to delete invalid expected LMDB size file: " + expectedDbFileSizeFile);
			}
			return missingExpectedDbFileSizes();
		}
	}

	private void writeExpectedDbFileSizes(DbFileSizes expectedDbFileSizes) throws IOException {
		var properties = new Properties();
		properties.setProperty(TRIPLES_DATA_SIZE_PROPERTY, Long.toString(expectedDbFileSizes.triplesDataSizeBytes));
		properties.setProperty(VALUES_DATA_SIZE_PROPERTY, Long.toString(expectedDbFileSizes.valuesDataSizeBytes));
		properties.setProperty(TRIPLE_INDEXES_PROPERTY, storeConfig.getTripleIndexes());
		if (externalStoreDirectoryEnabled()) {
			properties.setProperty(STORE_REUSE_CONFIRMED_FILE_PROPERTY,
					Boolean.toString(Boolean.getBoolean(REUSE_STORE_CONFIRMED_PROPERTY)));
			properties.setProperty(STORE_COMPATIBILITY_KEY_FILE_PROPERTY, storeCompatibilityKey());
		}
		try (var outputStream = new FileOutputStream(expectedDbFileSizeFile())) {
			properties.store(outputStream, "Expected LMDB data file sizes for ThemeQueryBenchmark");
		}
	}

	private long parseSizeProperty(Properties properties, String propertyName) {
		var value = properties.getProperty(propertyName);
		if (value == null) {
			throw new IllegalStateException("Missing property " + propertyName);
		}
		try {
			return Long.parseLong(value);
		} catch (NumberFormatException e) {
			throw new IllegalStateException("Invalid long value for property " + propertyName + ": " + value, e);
		}
	}

	private DbFileSizes missingExpectedDbFileSizes() {
		return new DbFileSizes(-1L, -1L);
	}

	private DbFileSizes currentDbFileSizes() {
		return new DbFileSizes(dbFileSize(TRIPLES_DATA_FILE), dbFileSize(VALUES_DATA_FILE));
	}

	private boolean hasExpectedDbFileSizes(DbFileSizes expectedDbFileSizes) {
		var currentDbFileSizes = currentDbFileSizes();
		return currentDbFileSizes.triplesDataSizeBytes == expectedDbFileSizes.triplesDataSizeBytes
				&& currentDbFileSizes.valuesDataSizeBytes == expectedDbFileSizes.valuesDataSizeBytes;
	}

	private File expectedDbFileSizeFile() {
		return new File(storeDirectory(), EXPECTED_DB_FILE_SIZES_FILE);
	}

	private long dbFileSize(String relativePath) {
		return new File(storeDirectory(), relativePath).length();
	}

	private void loadData() throws IOException {
		StopWatch started = StopWatch.createStarted();
		try (var connection = repository.getConnection()) {
			var inserter = new RDFInserter(connection);
//			System.out.println("Loading theme dataset: " + theme);
//			ThemeDataSetGenerator.generate(theme, inserter);
			for (var themeDataset : Theme.values()) {
				connection.begin(IsolationLevels.READ_COMMITTED);
				System.out.println("Loading theme dataset: " + themeDataset);
				ThemeDataSetGenerator.generate(themeDataset, inserter);
				connection.commit();
			}
		}
		started.stop();

		System.out.println("Loaded theme datasets in " + started);
	}

	private File storeDirectory() {
//		return new File(STORE_DIRECTORY, theme.name().toLowerCase());
		return new File(storeDirectoryRoot(), "complete");
	}

	private static File storeDirectoryRoot() {
		String configuredStoreDirectory = System.getProperty(STORE_DIRECTORY_PROPERTY);
		if (configuredStoreDirectory != null && !configuredStoreDirectory.isBlank()) {
			return new File(configuredStoreDirectory);
		}

		File target = new File("target", "lmdb-theme-query-benchmark");
		if (target.getAbsolutePath().toLowerCase(Locale.ROOT).contains(TARGET_DIRECTORY_ROOT)) {
			return target;
		}
		// In case the benchmark is run from an IDE with a different working directory, keep the default store
		// directory inside the lmdb module target directory.
		return new File(TARGET_DIRECTORY_ROOT + "target", "lmdb-theme-query-benchmark");
	}

	private static boolean externalStoreDirectoryEnabled() {
		String configuredStoreDirectory = System.getProperty(STORE_DIRECTORY_PROPERTY);
		return configuredStoreDirectory != null && !configuredStoreDirectory.isBlank();
	}

	private static void requireExternalStoreReuseConfirmation() {
		if (!externalStoreDirectoryEnabled()) {
			return;
		}
		if (!Boolean.getBoolean(REUSE_STORE_CONFIRMED_PROPERTY)) {
			throw new IllegalStateException("External LMDB benchmark store reuse requires confirming that no code "
					+ "changes affect the LMDB disk format or loaded benchmark data. Set -D"
					+ REUSE_STORE_CONFIRMED_PROPERTY + "=true after checking the current code changes.");
		}
	}

	private static String storeCompatibilityKey() {
		return System.getProperty(STORE_COMPATIBILITY_KEY_PROPERTY, DEFAULT_STORE_COMPATIBILITY_KEY);
	}

	private static void restoreSystemProperty(String propertyName, String propertyValue) {
		if (propertyValue == null) {
			System.clearProperty(propertyName);
		} else {
			System.setProperty(propertyName, propertyValue);
		}
	}

	private void captureQueryPlanSnapshot() throws IOException {
		var benchmarkQuery = ThemeQueryCatalog.benchmarkQueryFor(theme, z_queryIndex);
		var featureFlags = new FeatureFlagCollector()
				.addValue("themeBenchmark.themeName", () -> themeName)
				.addValue("themeBenchmark.queryIndex", () -> z_queryIndex)
				.addReflectiveGetter("lmdbStore.defaultIsolationLevel", store, "getDefaultIsolationLevel")
				.addReflectiveGetter("lmdbStore.writable", store, "isWritable")
				.addReflectiveGetter("lmdbConfig.tripleIndexes", storeConfig, "getTripleIndexes")
				.addReflectiveGetter("lmdbConfig.forceSync", storeConfig, "getForceSync")
				.addReflectiveField("lmdbConfig.autoGrow", storeConfig, "autoGrow")
				.addReflectiveGetter("lmdbConfig.valueDbSize", storeConfig, "getValueDBSize")
				.addReflectiveGetter("lmdbConfig.tripleDbSize", storeConfig, "getTripleDBSize");
		QueryPlanCapture.registerConfiguredFeatureFlags(featureFlags);

		var context = QueryPlanCaptureContext.builder()
				.outputDirectory(QueryPlanCapture.resolveOutputDirectory().resolve(STORE_NAME))
				.queryId(STORE_NAME + "-" + themeName + "-q" + z_queryIndex)
				.queryString(query)
				.benchmark("ThemeQueryBenchmark")
				.addMetadata("store", STORE_NAME)
				.addMetadata("theme", themeName)
				.addMetadata("queryIndex", Integer.toString(z_queryIndex))
				.addMetadata("queryName", benchmarkQuery.getName())
				.addMetadata("expectedCount", Long.toString(expected))
				.addMetadata(QueryPlanCapture.metadataFromSystemProperties())
				.featureFlagCollector(featureFlags)
				.tupleExprRenderer(this::renderTupleExprWithIr)
				.build();

		try (var connection = repository.getConnection()) {
			var snapshotPath = new QueryPlanCapture()
					.captureAndWrite(context, () -> connection.prepareTupleQuery(query));
			System.out.println("Query plan snapshot written to: " + snapshotPath);
		}
	}

	private String renderTupleExprWithIr(TupleExpr tupleExpr) {
		var config = new TupleExprIRRenderer.Config();
		config.verifyRoundTrip = false;
		return new TupleExprIRRenderer(config).render(tupleExpr);
	}

	TupleExpr explainOptimizedTupleExpr() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			Explanation explanation = connection.prepareTupleQuery(query).explain(Explanation.Level.Optimized);
			return (TupleExpr) explanation.tupleExpr();
		}
	}

	String explainTelemetry() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.READ_COMMITTED);
			try {
				Explanation explanation = connection.prepareTupleQuery(query).explain(Explanation.Level.Telemetry);
				connection.commit();
				return explanation.toString();
			} catch (RuntimeException | Error e) {
				connection.rollback();
				throw e;
			}
		}
	}

	EvaluationStatistics evaluationStatistics() {
		try {
			Method getBackingStore = LmdbStore.class.getDeclaredMethod("getBackingStore");
			getBackingStore.setAccessible(true);
			Object backingStore = getBackingStore.invoke(store);
			Method getEvaluationStatistics = backingStore.getClass().getDeclaredMethod("getEvaluationStatistics");
			getEvaluationStatistics.setAccessible(true);
			return (EvaluationStatistics) getEvaluationStatistics.invoke(backingStore);
		} catch (ReflectiveOperationException e) {
			throw new IllegalStateException("Unable to access benchmark evaluation statistics", e);
		}
	}

