	public void printCodegenExplain() {
		if (!Boolean.getBoolean(CODEGEN_EXPLAIN_PROPERTY)) {
			return;
		}
		System.out.println("### LMDB Codegen Explain ###");
		try {
			Class<?> factory = Class.forName("org.eclipse.rdf4j.sail.lmdb.LmdbGeneratedRecordIteratorFactory");
			Method getLastExplain = factory.getDeclaredMethod("getLastExplain");
			getLastExplain.setAccessible(true);
			Object explain = getLastExplain.invoke(null);
			System.out.println(explain == null ? "<none>" : explain);
			Method getRecentExplains = factory.getDeclaredMethod("getRecentExplains");
			getRecentExplains.setAccessible(true);
			Object recent = getRecentExplains.invoke(null);
			System.out.println(recent);
		} catch (ReflectiveOperationException e) {
			System.out.println("unavailable: " + e.getClass().getSimpleName() + ": " + e.getMessage());
		}
		System.out.println();
	}

	private void clearCodegenExplain() {
		if (!Boolean.getBoolean(CODEGEN_EXPLAIN_PROPERTY)) {
			return;
		}
		try {
			Class<?> factory = Class.forName("org.eclipse.rdf4j.sail.lmdb.LmdbGeneratedRecordIteratorFactory");
			Method clearRecentExplains = factory.getDeclaredMethod("clearRecentExplains");
			clearRecentExplains.setAccessible(true);
			clearRecentExplains.invoke(null);
		} catch (ReflectiveOperationException e) {
			throw new IllegalStateException("Unable to clear LMDB Janino explain entries", e);
		}
	}

	@Test
	public void firstRowBenchmarksUseReadCommitted() throws IOException {
		String source = Files.readString(new File(
				"src/test/java/org/eclipse/rdf4j/sail/lmdb/benchmark/ThemeQueryBenchmark.java").toPath(),
				StandardCharsets.UTF_8);
		String implementationSource = source.substring(0, source.indexOf("\n\t@Test"));
		int methodStart = source.indexOf("private long timeToFirstRows(int rowLimit)");
		int methodEnd = source.indexOf("\n\tprivate void ensureDataLoadedAndValidated()", methodStart);

		assertTrue(methodStart >= 0, "timeToFirstRows method must exist");
		assertTrue(methodEnd > methodStart, "timeToFirstRows method body must be isolated");
		assertTrue(
				source.substring(methodStart, methodEnd).contains("connection.begin(IsolationLevels.READ_COMMITTED)"),
				"time-to-first benchmark methods must use READ_COMMITTED so ID-based joins and Janino paths are eligible");
		assertTrue(source.contains("ConfigUtil.createStore(storeDirectory, storeConfig)"),
				"theme benchmark LMDB stores must default to READ_COMMITTED so explain and capture use the same isolation");
		assertTrue(implementationSource.contains("rdf4j.benchmark.printPlans"),
				"theme benchmark optimized and telemetry plan output must be explicitly opt-in");
		assertFalse(implementationSource.contains("!Boolean.getBoolean(PROFILING_PROPERTY)"),
				"theme benchmark must not print full plans by default during timed JMH trials");
		try {
			assertTrue(ThemeQueryBenchmark.class.getDeclaredMethod("printCodegenExplain").canAccess(this),
					"theme benchmark must expose codegen-explain diagnostics when the explain flag is enabled");
		} catch (NoSuchMethodException e) {
			throw new AssertionError("theme benchmark must print the last LMDB Janino explain entry for profiling runs",
					e);
		}
	}

	@Test
	public void externalStoreReuseRequiresExplicitCompatibilityConfirmation() throws IOException {
		String source = Files.readString(new File(
				"src/test/java/org/eclipse/rdf4j/sail/lmdb/benchmark/ThemeQueryBenchmark.java").toPath(),
				StandardCharsets.UTF_8);
		String implementationSource = source.substring(0, source.indexOf("\n\t@Test"));

		assertTrue(implementationSource.contains("rdf4j.lmdb.themeQueryBenchmark.storeDirectory"),
				"theme benchmark must support an external store directory");
		assertTrue(implementationSource.contains("rdf4j.lmdb.themeQueryBenchmark.reuseStoreConfirmed"),
				"external store reuse must require explicit compatibility confirmation");
		assertTrue(implementationSource.contains("rdf4j.lmdb.themeQueryBenchmark.storeCompatibilityKey"),
				"external store reuse must expose a compatibility key so callers can invalidate stale stores");
		assertTrue(implementationSource.contains("External LMDB benchmark store reuse requires confirming"),
				"external store reuse must fail fast until disk format and loaded data compatibility is confirmed");
	}

	@Test
	public void externalStoreReuseConfirmationGuardRejectsUnconfirmedStoreDirectory() {
		String previousStoreDirectory = System.getProperty(STORE_DIRECTORY_PROPERTY);
		String previousReuseConfirmed = System.getProperty(REUSE_STORE_CONFIRMED_PROPERTY);
		try {
			System.setProperty(STORE_DIRECTORY_PROPERTY, "/tmp/rdf4j-lmdb-theme-query-benchmark");
			System.clearProperty(REUSE_STORE_CONFIRMED_PROPERTY);

			var exception = assertThrows(IllegalStateException.class,
					ThemeQueryBenchmark::requireExternalStoreReuseConfirmation);
			assertTrue(exception.getMessage().contains(REUSE_STORE_CONFIRMED_PROPERTY),
					"guard error must tell benchmark users which confirmation flag to set");

			System.setProperty(REUSE_STORE_CONFIRMED_PROPERTY, "true");
			requireExternalStoreReuseConfirmation();
		} finally {
			restoreSystemProperty(STORE_DIRECTORY_PROPERTY, previousStoreDirectory);
			restoreSystemProperty(REUSE_STORE_CONFIRMED_PROPERTY, previousReuseConfirmed);
		}
	}

